      alias: 'operator'
    },
    'primitive-1-operators': {
      pattern: /[`ЛңЛҳВЁвҒјвҢңВҙЛқЛҷ]/,
      alias: 'operator'
    },
    'primitive-2-operators': {
      pattern: /[вҲҳвҠёвҹңв—ӢвҢҫвҺүвҡҮвҚҹвҠҳв—¶вҺҠ]/,
